class ProductLabelManager{constructor(){this.language=Shopify.locale,this.body=$("body"),this.oldHref=window.location.href,this.init()}init(){this.setupInitialLabels(),this.setupUrlChangeListener(),this.setupCustomEventListeners()}setupInitialLabels(){setTimeout((()=>{this.setProductBlockLabels(),this.isProductPage()&&this.setProductPageLabels()}),1e3)}setupUrlChangeListener(){setInterval((()=>{window.location.href!==this.oldHref&&(this.oldHref=window.location.href,setTimeout((()=>{this.setProductBlockLabels(),this.isProductPage()&&this.setProductPageLabels()}),500))}),100)}setupCustomEventListeners(){document.addEventListener("onurlchanged",(()=>{setTimeout((()=>this.setProductBlockLabels()),1e3)}))}isProductPage(){return window.location.href.includes("/products/")}normalizeTag(e){return e.toLowerCase().trim()}generateLabelHTML(e,t){const s="en"===this.language?e.message:e.message_fr;return`\n            <span class="${`product-label product-label--sale product-label-${t}`}">\n                <span style="background-color:${e.bg_color};color:${e.fg_color};">${s}</span>\n            </span>\n        `}mergeLabelContainers(e){if(e.length<=1)return e.first();const t=e.first();for(let s=1;s<e.length;s++)t.append(e.eq(s).html()),e.eq(s).remove();return t}getLabelsForTags(e,t=""){let s=t||"";if(!e||!app_settings?.product_labels)return s;const o=new Set;return Object.keys(app_settings.product_labels).forEach((t=>{const l=app_settings.product_labels[t],n=l.tags.split(",");for(let t of n){const n=this.normalizeTag(t);e.includes(n)&&!o.has(n)&&(s.includes("product-label-"+n)||(s+=this.generateLabelHTML(l,n),o.add(n)))}})),s}setProductBlockLabels(){this.body.find("product-block").each(((e,t)=>{const s=$(t),o=s.attr("data-tags");if(s.closest("#product-crosssell-carousel").length)return;const l=s.find(".product-label-container");if(0===l.length)return;const n=this.mergeLabelContainers(l);console.log("Element exists:",n.length>0),console.log("Element HTML (outer):",n[0].outerHTML),console.log("Child nodes count:",n[0].children.length),console.log("Child elements:",n.children()),setTimeout((()=>{console.log("Labels after delay:",n.html())}),1e3);const a=n.html(),r=this.getLabelsForTags(o,a);r&&r!==a&&n.html(r)}))}setProductPageLabels(){const e=this.body.find("product-form").data("tags");if(!e)return;const t=this.body.find(".main-image").find("variant-content");let s=t.find(".product-label-container");0===s.length&&(s=$('<div class="product-label-container"></div>'),t.append(s));const o=this.mergeLabelContainers(s),l=o.html(),n=this.getLabelsForTags(e,l);n&&n!==l&&o.html(n)}}$(document).ready((()=>{window.productLabelManager=new ProductLabelManager,window.setProductBlockLabels=()=>productLabelManager.setProductBlockLabels(),window.setProductPageLabels=()=>productLabelManager.setProductPageLabels()}));